#include <stdio.h>
#include <stdbool.h>

bool isPrime(int num) {
   if (num <= 1) return false;
   for (int i = 2; i * i <= num; i++) {
      if (num % i == 0) return false;
   }
   return true;
}

int kthPrime(int k) {
   int count = 0;
   int num = 2;
   while (true) {
      if (isPrime(num)) {
         count++;
         if (count == k) return num;
      }
      num++;
   }
}

int main() {
   int k;
   scanf("%d", &k);
   printf("%d\n", kthPrime(k));
   return 0;
}

